const seoData = JSON.parse($node["Agent Alpha [SEO Director]"].json.message.content);
const finalHtml = $node["Agent Delta [The Auditor]"].json.message.content;
const rawData = $node["Parse XML & Select Top 3"].json;

return {
  json: {
    title: seoData.headline,
    slug: seoData.slug,
    content: finalHtml,
    image_url: rawData.image_url,
    featured_image: rawData.image_url,
    status: "published",
    content_type: "blog",
    category: "Market Analysis"
  }
};
